public extension URL {
    var persistentIdentifier: PersistentIdentifier? {
        guard scheme == "x-coredata",
              let host = host()
        else {
            return nil
        }
        let pathComponents = self.pathComponents
        guard pathComponents.count == 3 else {
            return nil
        }
        let entityName = pathComponents[1]
        let primaryKey = pathComponents[2]
        let json = PersistentIdentifierJSON(
            implementation: .init(primaryKey: primaryKey,
                                  uriRepresentation: self,
                                  isTemporary: false,
                                  storeIdentifier: host,
                                  entityName: entityName)
        )
        let encoder = JSONEncoder()
        guard let data = try? encoder.encode(json) else {
            return nil
        }
        let decoder = JSONDecoder()
        return try? decoder.decode(PersistentIdentifier.self, from: data)
    }
}

public extension PersistentIdentifier {
    private var _implementation: Any? {
        guard let implementation = getMirrorChildValue(of: self, childName: "implementation") else {
            return nil
        }
        return implementation
    }
    var objectID: NSManagedObjectID? {
        guard let _implementation, let objectID = getMirrorChildValue(of: _implementation, childName: "managedObjectID") as? NSManagedObjectID else {
            return nil
        }
        return objectID
    }
    var uriRepresentation: URL? {
        objectID?.uriRepresentation()
    }
    var isTemporary: Bool? {
        guard let _implementation, let isTemporary = getMirrorChildValue(of: _implementation, childName: "isTemporary") as? Bool else {
            return nil
        }
        return isTemporary
    }
}
